        </div>

        {/* Decorative Corners */}
        <div className="absolute top-4 left-4 w-4 h-4 border-t border-l border-white/20"></div>
        <div className="absolute top-4 right-4 w-4 h-4 border-t border-r border-white/20"></div>
        <div className="absolute bottom-4 left-4 w-4 h-4 border-b border-l border-white/20"></div>
        <div className="absolute bottom-4 right-4 w-4 h-4 border-b border-r border-white/20"></div>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Send, Mic, Image as ImageIcon, Terminal, X, 
  Activity, ChevronLeft, LayoutGrid, BrainCircuit, 
  Globe, Zap, ScanEye, Wand2, Paperclip, Shield, Skull, Cpu, 
  Volume2, VolumeX, Trash2, Radio, StopCircle, Settings2, ChevronDown,
  AlertTriangle, CheckCircle2
} from 'lucide-react';
import { Message, Role, CodeSnippet, Attachment, GenerationMode, AstraMode, VoiceSettings } from '../types';
import { 
  sendMessageToGemini, 
  initializeChat, 
  generateEditedImage, 
  runAstraDetection,
  speakText,
  AstraLiveSession
} from '../services/geminiService';
import { 
  INITIAL_GREETING_SHIELD, 
  INITIAL_GREETING_SKULL, 
  INITIAL_GREETING_ROOT 
} from '../constants';
import ReactMarkdown from 'react-markdown';
import { Logo } from './Logo';
import { motion, AnimatePresence } from 'framer-motion';
import { Typewriter } from './Typewriter';
import { AstraScanner } from './AstraScanner';
import { MatrixRain } from './MatrixRain';
import { VoiceVisualizer } from './VoiceVisualizer';
import { Content } from '@google/genai';

interface ChatInterfaceProps {
  onBack: () => void;
}

const DEFAULT_VOICE_SETTINGS: VoiceSettings = {
    shield: { pitch: 1.0, rate: 1.0, voiceURI: '' },
    skull: { pitch: 0.1, rate: 0.6, voiceURI: '' }, // Default Demon
    root: { pitch: 0.8, rate: 1.4, voiceURI: '' } // Default Robot
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onBack }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [genMode, setGenMode] = useState<GenerationMode>('CHAT');
  const [astraMode, setAstraMode] = useState<AstraMode>('shield'); 
  const [attachment, setAttachment] = useState<Attachment | null>(null);
  const [toolBoxOpen, setToolBoxOpen] = useState(false);
  const [featureMenuOpen, setFeatureMenuOpen] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(false);
  const [scanningImage, setScanningImage] = useState<string | null>(null);
  const [isLiveMode, setIsLiveMode] = useState(false);

  // Voice Customization State
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(DEFAULT_VOICE_SETTINGS);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [configMode, setConfigMode] = useState<AstraMode>('shield'); // Which mode are we editing in settings

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isInitialized = useRef(false);
  const liveSessionRef = useRef<AstraLiveSession | null>(null);

  // --- INIT & LOAD HISTORY ---
  useEffect(() => {
    if (isInitialized.current) return;
    isInitialized.current = true;

    const savedHistory = localStorage.getItem('ASTRA_HISTORY');
    const savedAstraMode = localStorage.getItem('ASTRA_MODE') as AstraMode;
    const savedGenMode = localStorage.getItem('ASTRA_GEN_MODE') as GenerationMode;
    const savedVoiceSettings = localStorage.getItem('ASTRA_VOICE_SETTINGS');

    if(savedVoiceSettings) {
        try {
            setVoiceSettings(JSON.parse(savedVoiceSettings));
        } catch(e) { console.error("Error loading voice settings", e); }
    }

    if (savedHistory && savedAstraMode) {
       try {
           const parsedMsgs = JSON.parse(savedHistory);
           setMessages(parsedMsgs);
           setAstraMode(savedAstraMode);
           if(savedGenMode) setGenMode(savedGenMode);

           const history: Content[] = parsedMsgs
             .filter((m: Message) => m.id !== 'init' && !m.text.startsWith('>> IMAGE_GENERATED')) 
             .map((m: Message) => ({ 
                 role: m.role === Role.USER ? 'user' : 'model', 
                 parts: [{ text: m.text }] 
             }));

           initializeChat(savedGenMode || 'CHAT', savedAstraMode, history);
       } catch (e) {
           console.error("Corrupt History", e);
           startFreshSession('shield', 'CHAT');
       }
    } else {
       startFreshSession('shield', 'CHAT');
    }

    // Load Voices
    const loadVoices = () => {
        const voices = window.speechSynthesis.getVoices();
        setAvailableVoices(voices);
    };
    window.speechSynthesis.onvoiceschanged = loadVoices;
    loadVoices();

  }, []);

  // --- SAVE HISTORY ---
  useEffect(() => {
     if (isInitialized.current) {
        localStorage.setItem('ASTRA_HISTORY', JSON.stringify(messages));
        localStorage.setItem('ASTRA_MODE', astraMode);
        localStorage.setItem('ASTRA_GEN_MODE', genMode);
        localStorage.setItem('ASTRA_VOICE_SETTINGS', JSON.stringify(voiceSettings));
     }
  }, [messages, astraMode, genMode, voiceSettings]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- VOICE OUTPUT ---
  useEffect(() => {
      if (isVoiceEnabled && messages.length > 0) {
          const lastMsg = messages[messages.length - 1];
          if (lastMsg.role === Role.MODEL && !isLoading && lastMsg.id !== 'init') {
             speakText(lastMsg.text, astraMode, voiceSettings[astraMode]);
          }
      } else {
          speakText('', astraMode, undefined, true);
      }
  }, [messages, isVoiceEnabled, isLoading, astraMode, voiceSettings]);

  const startFreshSession = (newAstraMode: AstraMode, newGenMode: GenerationMode) => {
      initializeChat(newGenMode, newAstraMode);

      let greeting = INITIAL_GREETING_SHIELD;
      if (newAstraMode === 'skull') greeting = INITIAL_GREETING_SKULL;
      if (newAstraMode === 'root') greeting = INITIAL_GREETING_ROOT;

      setMessages([{
        id: 'init',
        role: Role.MODEL,
        text: greeting,
        timestamp: Date.now()
      }]);
  };

  const switchProtocol = (newMode: AstraMode) => {
      setAstraMode(newMode);
      startFreshSession(newMode, genMode);
  };

  const switchGenMode = (newMode: GenerationMode) => {
      setGenMode(newMode);
      setToolBoxOpen(false);
      setFeatureMenuOpen(false);
      startFreshSession(astraMode, newMode);
  };

  const clearHistory = () => {
      localStorage.removeItem('ASTRA_HISTORY');
      localStorage.removeItem('ASTRA_MODE');
      localStorage.removeItem('ASTRA_GEN_MODE');
      startFreshSession(astraMode, genMode);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          const reader = new FileReader();
          reader.onload = (ev) => {
              if (ev.target?.result) {
                  setAttachment({
                      file,
                      previewUrl: URL.createObjectURL(file),
                      base64: (ev.target.result as string).split(',')[1],
                      mimeType: file.type
                  });
              }
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSend = async () => {
    if ((!input.trim() && !attachment) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      text: input,
      image: attachment?.previewUrl,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    const currentAttachment = attachment;
    setAttachment(null);
    setIsLoading(true);

    if (genMode === 'ASTRA_DETECTION' && currentAttachment?.previewUrl) {
        setScanningImage(currentAttachment.previewUrl);
    }

    const modelMsgId = (Date.now() + 1).toString();
    const updateModelMsg = (text: string) => {
        setMessages(prev => {
            const exists = prev.find(m => m.id === modelMsgId);
            if (exists) return prev.map(m => m.id === modelMsgId ? { ...m, text } : m);
            return [...prev, { id: modelMsgId, role: Role.MODEL, text, timestamp: Date.now() }];
        });
    };

    try {
        if (genMode === 'IMAGE_EDIT') {
            updateModelMsg('>> RENDERING_VISUAL_DATA...');
            const imgBase64 = await generateEditedImage(userMsg.text, currentAttachment?.base64, currentAttachment?.mimeType);
            if (imgBase64) {
                setMessages(prev => prev.map(m => m.id === modelMsgId ? { ...m, text: ">> IMAGE_GENERATED.", image: imgBase64 } : m));
            } else {
                updateModelMsg(">> ERROR: RENDER FAILED.");
            }
        } else if (genMode === 'ASTRA_DETECTION') {
            if (currentAttachment) {
                const result = await runAstraDetection(currentAttachment, (text) => {});
                updateModelMsg(result);
            }
        } else {
            if (astraMode === 'root') updateModelMsg('> [EXECUTING_ROOT_COMMAND]...');
            await sendMessageToGemini(userMsg.text, currentAttachment, genMode, astraMode, updateModelMsg);
        }
    } catch (error) {
        updateModelMsg(">> SYSTEM FAILURE.");
    }
    setIsLoading(false);
    setScanningImage(null);
  };

  const toggleLiveSession = () => {
      if (isLiveMode) {
          liveSessionRef.current?.stop();
          liveSessionRef.current = null;
          setIsLiveMode(false);
      } else {
          setIsLiveMode(true);
          const session = new AstraLiveSession(astraMode);
          session.start(() => {
              setIsLiveMode(false);
              liveSessionRef.current = null;
          });
          liveSessionRef.current = session;
      }
  };

  const updateVoiceSetting = (key: keyof VoiceSettings['shield'], value: any) => {
      setVoiceSettings(prev => ({
          ...prev,
          [configMode]: {
              ...prev[configMode],
              [key]: value
          }
      }));
  };

  const getModeIcon = (m: GenerationMode) => {
      switch(m) {
          case 'DEEP_THINK': return BrainCircuit;
          case 'WEB_INTEL': return Globe;
          case 'SPEED_RUN': return Zap;
          case 'IMAGE_EDIT': return ImageIcon;
          case 'ASTRA_DETECTION': return ScanEye;
          case 'LOGO_ARCHITECT': return Wand2;
          default: return Terminal;
      }
  }

  const getThemeClasses = () => {
      switch(astraMode) {
          case 'skull': return 'bg-red-950 text-red-100 font-sans'; 
          case 'root': return 'bg-black text-red-500 font-terminal crt-scanlines'; 
          default: return 'bg-black text-white font-sans'; // Shield
      }
  };

  const features = [
      { id: 'CHAT', label: 'CORE CHAT', desc: 'Standard Astra Intelligence', icon: Terminal },
      { id: 'DEEP_THINK', label: 'DEEP REASONING', desc: 'Complex Problem Solving (High IQ)', icon: BrainCircuit },
      { id: 'WEB_INTEL', label: 'WEB INTEL', desc: 'Live Internet Access & Search', icon: Globe },
      { id: 'SPEED_RUN', label: 'SPEED RUN', desc: 'Lightning Fast Responses', icon: Zap },
      { id: 'IMAGE_EDIT', label: 'VISION EDIT', desc: 'Modify Images via Prompt', icon: ImageIcon },
      { id: 'ASTRA_DETECTION', label: 'DEEPFAKE SCAN', desc: 'Forensic Image Analysis', icon: ScanEye },
      { id: 'LOGO_ARCHITECT', label: 'LOGO ARCHITECT', desc: 'SVG Design & Vector Gen', icon: Wand2 },
  ];

  const CurrentModeIcon = getModeIcon(genMode);

  return (
    <div className={`fixed inset-0 z-50 flex flex-col h-[100dvh] w-full overflow-hidden ${getThemeClasses()}`}>

      {astraMode === 'root' && (
          <>
             <MatrixRain />
             <div className="fixed inset-0 z-0 flex items-center justify-center opacity-20 pointer-events-none animate-pulse">
                <Logo className="w-[500px] h-[500px]" isHackerMode={true} />
             </div>
             <div className="fixed inset-0 bg-red-500/5 z-0 pointer-events-none animate-pulse"></div>
          </>
      )}

      {/* --- HEADER --- */}
      <header className={`relative z-50 flex flex-col ${astraMode === 'root' ? 'bg-black/90' : 'bg-black/60 backdrop-blur-xl'} border-b border-white/10 transition-colors duration-500`}>

        <div className="flex items-center justify-between p-3 relative">
            {/* LEFT: LOGO & BACK */}
            <div className="flex items-center gap-3 w-1/4">
                <button onClick={onBack} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                    <Logo className="w-8 h-8" isHackerMode={astraMode === 'root'} />
                </button>
            </div>

            {/* CENTER: FEATURE DROPDOWN (STRICTLY CENTERED) */}
            <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-50">
                 <div className="relative">
                    <button 
                      onClick={() => setFeatureMenuOpen(!featureMenuOpen)}
                      className={`flex items-center gap-3 px-6 py-2.5 rounded-full border border-white/10 hover:border-astra-blue/50 transition-all group backdrop-blur-md shadow-lg ${astraMode === 'root' ? 'bg-red-900/40 text-red-500' : 'bg-white/5 text-astra-blue'}`}
                    >
                        <CurrentModeIcon size={18} className="group-hover:animate-pulse text-astra-saffron" />
                        <span className="font-orbitron text-xs font-bold tracking-wider hidden sm:inline-block">{genMode.replace('_', ' ')}</span>
                        <ChevronDown size={14} className={`transition-transform duration-300 opacity-60 ${featureMenuOpen ? 'rotate-180' : ''}`} />
                    </button>

                    <AnimatePresence>
                        {featureMenuOpen && (
                            <>
                            {/* Backdrop to close menu */}
                            <div className="fixed inset-0 z-40" onClick={() => setFeatureMenuOpen(false)}></div>

                            <motion.div
                              initial={{ opacity: 0, y: -10, scale: 0.95, x: "-50%" }}
                              animate={{ opacity: 1, y: 0, scale: 1, x: "-50%" }}
                              exit={{ opacity: 0, y: -10, scale: 0.95, x: "-50%" }}
                              className="absolute top-full left-1/2 mt-3 w-[280px] sm:w-[320px] bg-[#050505]/95 backdrop-blur-2xl border border-white/15 rounded-2xl overflow-hidden shadow-[0_10px_40px_rgba(0,0,0,0.8)] flex flex-col z-50"
                            >
                                <div className="px-5 py-3 bg-white/5 text-[10px] font-orbitron tracking-widest text-gray-400 uppercase border-b border-white/10 flex items-center justify-between">
                                    <span>Select Protocol</span>
                                    <Activity size={12} className="text-astra-blue" />
                                </div>
                                <div className="max-h-[60vh] overflow-y-auto custom-scrollbar p-2 space-y-1">
                                    {features.map((f) => (
                                        <button
                                          key={f.id}
                                          onClick={() => switchGenMode(f.id as GenerationMode)}
                                          className={`w-full flex items-center gap-4 px-3 py-3 rounded-xl transition-all text-left border border-transparent group ${genMode === f.id ? 'bg-astra-blue/10 border-astra-blue/30' : 'hover:bg-white/5 hover:border-white/10'}`}
                                        >
                                            <div className={`p-2 rounded-lg ${genMode === f.id ? 'bg-astra-saffron text-black' : 'bg-white/10 text-gray-400 group-hover:text-white'}`}>
                                                <f.icon size={18} />
                                            </div>
                                            <div className="flex-1">
                                                <div className={`font-orbitron text-xs font-bold tracking-wide ${genMode === f.id ? 'text-white' : 'text-gray-300 group-hover:text-white'}`}>
                                                    {f.label}
                                                </div>
                                                <div className="text-[10px] text-gray-500 font-tech leading-tight mt-0.5 group-hover:text-gray-400">
                                                    {f.desc}
                                                </div>
                                            </div>
                                            {genMode === f.id && <div className="w-1.5 h-1.5 rounded-full bg-astra-saffron shadow-[0_0_8px_#FF9933]"></div>}
                                        </button>
                                    ))}
                                </div>
                            </motion.div>
                            </>
                        )}
                    </AnimatePresence>
                 </div>
            </div>

            {/* RIGHT: TOOLS */}
            <div className="flex items-center justify-end gap-2 w-1/4">

                {/* PURGE BUTTON */}
                <button 
                    onClick={clearHistory}
                    className="flex items-center justify-center w-8 h-8 sm:w-auto sm:px-3 sm:py-2 bg-red-500/10 border border-red-500/30 hover:bg-red-500/20 hover:border-red-500/60 text-red-500 rounded-lg transition-all"
                    title="Wipe Chat Memory"
                >
                    <Trash2 size={16} />
                    <span className="hidden sm:inline ml-2 text-[10px] font-orbitron tracking-widest">PURGE</span>
                </button>

                 {/* Astra Mode Toggle (Mini) - Hidden on very small screens, integrated elsewhere if needed */}
                 <div className="hidden xl:flex items-center gap-1 bg-white/5 rounded-lg p-1 mr-1 border border-white/10">
                    <button onClick={() => switchProtocol('shield')} className={`p-1.5 rounded ${astraMode === 'shield' ? 'bg-astra-blue/20 text-astra-blue' : 'text-gray-500 hover:text-white'}`} title="Shield Mode"><Shield size={14} /></button>
                    <button onClick={() => switchProtocol('skull')} className={`p-1.5 rounded ${astraMode === 'skull' ? 'bg-red-500/20 text-red-500' : 'text-gray-500 hover:text-white'}`} title="Toxic Mode"><Skull size={14} /></button>
                    <button onClick={() => switchProtocol('root')} className={`p-1.5 rounded ${astraMode === 'root' ? 'bg-green-500/20 text-green-500' : 'text-gray-500 hover:text-white'}`} title="Root Mode"><Terminal size={14} /></button>
                 </div>

                <button 
                  onClick={() => setIsVoiceEnabled(!isVoiceEnabled)}
                  className={`p-2 rounded-lg transition-all border border-transparent ${isVoiceEnabled ? 'bg-astra-saffron text-black shadow-[0_0_10px_#FF9933]' : 'bg-white/5 text-gray-400 hover:text-white hover:border-white/20'}`}
                >
                    {isVoiceEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                </button>

                <button 
                   onClick={() => setToolBoxOpen(true)}
                   className="p-2 text-gray-400 hover:text-white transition-colors hover:rotate-90 duration-500"
                >
                    <Settings2 size={18} />
                </button>
            </div>
        </div>

        {/* SUB-HEADER STATUS BANNER (Cleaner) */}
        <div className="w-full h-1 bg-gradient-to-r from-transparent via-white/10 to-transparent"></div>

      </header>

      {/* --- MAIN CHAT AREA --- */}
      <main className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scroll-smooth pb-32">
        {messages.map((msg) => (
          <motion.div 
            key={msg.id}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className={`flex ${msg.role === Role.USER ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`max-w-[85%] md:max-w-[70%] relative group ${
                msg.role === Role.USER 
                 ? 'bg-white/10 border border-white/5 rounded-2xl rounded-tr-none' 
                 : astraMode === 'root' 
                   ? 'bg-black border border-green-500/30 rounded-none p-4 font-terminal text-green-400'
                   : 'bg-black/40 border border-white/10 rounded-2xl rounded-tl-none backdrop-blur-sm'
            } p-4`}>

                {/* Header for Message */}
                <div className="flex items-center gap-2 mb-2 opacity-50 text-[10px] font-orbitron tracking-widest">
                    {msg.role === Role.USER ? (
                        <><span>OPERATOR</span><div className="w-1 h-1 bg-astra-saffron rounded-full"></div></>
                    ) : (
                        <>
                          <div className={`w-1 h-1 rounded-full ${astraMode === 'skull' ? 'bg-red-500' : astraMode === 'root' ? 'bg-green-500' : 'bg-astra-blue'}`}></div>
                          <span>ASTRA // {astraMode.toUpperCase()}</span>
                        </>
                    )}
                    <span>{new Date(msg.timestamp).toLocaleTimeString()}</span>
                </div>

                {/* Attachments */}
                {msg.image && (
                    <div className="mb-3 rounded-lg overflow-hidden border border-white/10 relative group-hover:border-astra-blue/50 transition-colors">
                        <img src={msg.image} alt="Upload" className="max-w-full max-h-64 object-cover" />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
                    </div>
                )}

                {/* Text Content */}
                <div className={`prose prose-invert prose-p:leading-relaxed prose-pre:bg-black/50 prose-pre:border prose-pre:border-white/10 ${astraMode === 'root' ? 'font-terminal text-lg' : 'font-light'}`}>
                   {msg.id === messages[messages.length - 1].id && msg.role === Role.MODEL && isLoading ? (
                       <Typewriter text={msg.text} speed={astraMode === 'root' ? 5 : 15} />
                   ) : (
                       <ReactMarkdown
                        components={{
                            code({className, children, ...props}) {
                                const match = /language-(\w+)/.exec(className || '')
                                return match ? (
                                    <div className="relative group/code my-4">
                                        <div className="absolute -top-3 left-2 px-2 bg-gray-800 text-[10px] text-gray-400 rounded border border-gray-700 font-mono">
                                            {match[1].toUpperCase()}
                                        </div>
                                        <div className="bg-[#0d0d0d] p-4 rounded-lg border border-white/10 overflow-x-auto">
                                            <code className={`!bg-transparent text-sm font-mono text-gray-300 ${className}`} {...props}>
                                                {children}
                                            </code>
                                        </div>
                                    </div>
                                ) : (
                                    <code className="bg-white/10 px-1 py-0.5 rounded text-astra-saffron font-mono text-xs" {...props}>
                                        {children}
                                    </code>
                                )
                            }
                        }}
                       >
                           {msg.text}
                       </ReactMarkdown>
                   )}
                </div>
            </div>
          </motion.div>
        ))}
        {isLoading && (
            <div className="flex justify-start">
               <div className="flex items-center gap-1 h-6">
                   <div className="w-1 h-1 bg-astra-blue rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                   <div className="w-1 h-1 bg-astra-blue rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                   <div className="w-1 h-1 bg-astra-blue rounded-full animate-bounce"></div>
               </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </main>

      {/* --- INPUT AREA --- */}
      <div className={`p-4 ${astraMode === 'root' ? 'bg-black border-t-2 border-green-500' : 'bg-black/60 backdrop-blur-xl border-t border-white/10'}`}>

         {/* ATTACHMENT PREVIEW */}
         <AnimatePresence>
             {attachment && (
                 <motion.div 
                   initial={{ opacity: 0, y: 10 }}
                   animate={{ opacity: 1, y: 0 }}
                   exit={{ opacity: 0, y: 10 }}
                   className="absolute bottom-full left-4 mb-4 bg-gray-900 border border-white/20 p-2 rounded-lg flex items-center gap-3"
                 >
                     <div className="w-10 h-10 rounded overflow-hidden">
                         <img src={attachment.previewUrl} className="w-full h-full object-cover" />
                     </div>
                     <div className="text-xs max-w-[150px] truncate">{attachment.file.name}</div>
                     <button onClick={() => setAttachment(null)} className="p-1 hover:bg-white/20 rounded-full"><X size={14} /></button>
                 </motion.div>
             )}
         </AnimatePresence>

         <div className="max-w-4xl mx-auto flex gap-3 items-end">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*"
              onChange={handleFileSelect}
            />

            <button 
              onClick={() => fileInputRef.current?.click()}
              className={`p-3 rounded-xl transition-colors ${astraMode === 'root' ? 'border border-green-500 text-green-500 hover:bg-green-500/20' : 'bg-white/5 text-gray-400 hover:text-astra-blue hover:bg-white/10'}`}
            >
                <Paperclip size={20} />
            </button>

            <button
               onClick={toggleLiveSession}
               className={`p-3 rounded-xl transition-all relative ${isLiveMode ? 'bg-red-500 text-white animate-pulse' : astraMode === 'root' ? 'border border-green-500 text-green-500 hover:bg-green-500/20' : 'bg-white/5 text-gray-400 hover:text-astra-blue hover:bg-white/10'}`}
            >
                {isLiveMode ? <StopCircle size={20} /> : <Radio size={20} />}
            </button>

            <div className={`flex-1 flex items-center gap-2 p-3 rounded-xl ${astraMode === 'root' ? 'border border-green-500 bg-black' : 'bg-white/5 border border-white/5 focus-within:border-astra-blue/50'}`}>
                {astraMode === 'root' && <span className="text-green-500 font-terminal mr-1">{'>'}</span>}
                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => {
                      if(e.key === 'Enter' && !e.shiftKey) {
                          e.preventDefault();
                          handleSend();
                      }
                  }}
                  placeholder={astraMode === 'skull' ? "Say something stupid..." : astraMode === 'root' ? "ENTER_COMMAND_MATRIX..." : "Message Astra..."}
                  className={`bg-transparent w-full resize-none outline-none max-h-32 text-sm ${astraMode === 'root' ? 'font-terminal text-green-500 placeholder-green-800' : 'text-white placeholder-gray-500'}`}
                  rows={1}
                />
            </div>

            <button 
              onClick={handleSend}
              disabled={isLoading || (!input.trim() && !attachment)}
              className={`p-3 rounded-xl transition-all disabled:opacity-50 ${
                  astraMode === 'root' 
                  ? 'bg-green-600 text-black hover:bg-green-500' 
                  : 'bg-astra-blue text-black hover:bg-astra-blue/80 shadow-[0_0_15px_rgba(0,240,255,0.3)]'
              }`}
            >
                <Send size={20} />
            </button>
         </div>
      </div>

      {/* --- SETTINGS MODAL (Reused for Config) --- */}
      <AnimatePresence>
          {toolBoxOpen && (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-4"
              >
                  <div className="bg-gray-900 border border-white/10 w-full max-w-md rounded-2xl p-6 relative shadow-2xl">
                      <button onClick={() => setToolBoxOpen(false)} className="absolute top-4 right-4 text-gray-500 hover:text-white"><X size={20} /></button>

                      <h2 className="font-orbitron text-xl mb-6 flex items-center gap-2">
                          <Settings2 className="text-astra-saffron" />
                          SYSTEM CONFIG
                      </h2>

                      {/* Config Mode Tabs */}
                      <div className="flex bg-black/50 rounded-lg p-1 mb-6">
                         {(['shield', 'skull', 'root'] as AstraMode[]).map(m => (
                             <button
                               key={m}
                               onClick={() => setConfigMode(m)}
                               className={`flex-1 py-2 text-xs font-bold rounded uppercase transition-colors ${configMode === m ? 'bg-white/10 text-astra-blue' : 'text-gray-500'}`}
                             >
                                 {m}
                             </button>
                         ))}
                      </div>

                      <div className="space-y-6">
                          <div>
                              <label className="text-xs font-tech text-gray-400 mb-2 block">VOICE PROFILE</label>
                              <select 
                                className="w-full bg-black border border-white/20 rounded p-2 text-sm text-white"
                                value={voiceSettings[configMode].voiceURI}
                                onChange={(e) => updateVoiceSetting('voiceURI', e.target.value)}
                              >
                                  <option value="">System Default</option>
                                  {availableVoices.map(v => (
                                      <option key={v.voiceURI} value={v.voiceURI}>{v.name} ({v.lang})</option>
                                  ))}
                              </select>
                          </div>

                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="text-xs font-tech text-gray-400 mb-2 block">PITCH: {voiceSettings[configMode].pitch.toFixed(1)}</label>
                                  <input 
                                    type="range" min="0" max="2" step="0.1"
                                    value={voiceSettings[configMode].pitch}
                                    onChange={(e) => updateVoiceSetting('pitch', parseFloat(e.target.value))}
                                    className="w-full accent-astra-saffron"
                                  />
                              </div>
                              <div>
                                  <label className="text-xs font-tech text-gray-400 mb-2 block">SPEED: {voiceSettings[configMode].rate.toFixed(1)}</label>
                                  <input 
                                    type="range" min="0.1" max="2" step="0.1"
                                    value={voiceSettings[configMode].rate}
                                    onChange={(e) => updateVoiceSetting('rate', parseFloat(e.target.value))}
                                    className="w-full accent-astra-blue"
                                  />
                              </div>
                          </div>
                      </div>

                      <div className="mt-8 pt-6 border-t border-white/10 flex justify-end">
                          <button onClick={() => setToolBoxOpen(false)} className="px-6 py-2 bg-white text-black font-bold rounded hover:bg-gray-200">
                              SAVE CHANGES
                          </button>
                      </div>
                  </div>
              </motion.div>
          )}
      </AnimatePresence>

      {/* --- SCANNERS & OVERLAYS --- */}
      {scanningImage && <AstraScanner imageUrl={scanningImage} />}
      {isVoiceEnabled && !isLoading && <div className="absolute top-20 right-4 pointer-events-none opacity-50"><VoiceVisualizer /></div>}

    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Send, Mic, Image as ImageIcon, Terminal, X, 
  Activity, ChevronLeft, LayoutGrid, BrainCircuit, 
  Globe, Zap, ScanEye, Wand2, Paperclip, Shield, Skull, Cpu, 
  Volume2, VolumeX, Trash2, Radio, StopCircle, Settings2, ChevronDown,
  AlertTriangle, CheckCircle2, Flame
} from 'lucide-react';
import { Message, Role, CodeSnippet, Attachment, GenerationMode, AstraMode, VoiceSettings } from '../types';
import { 
  sendMessageToGemini, 
  initializeChat, 
  generateEditedImage, 
  runAstraDetection,
  speakText,
  AstraLiveSession
} from '../services/geminiService';
import { 
  INITIAL_GREETING_SHIELD, 
  INITIAL_GREETING_SKULL, 
  INITIAL_GREETING_ROOT 
} from '../constants';
import ReactMarkdown from 'react-markdown';
import { Logo } from './Logo';
import { motion, AnimatePresence } from 'framer-motion';
import { Typewriter } from './Typewriter';
import { AstraScanner } from './AstraScanner';
import { MatrixRain } from './MatrixRain';
import { VoiceVisualizer } from './VoiceVisualizer';
import { Content } from '@google/genai';

interface ChatInterfaceProps {
  onBack: () => void;
}

const DEFAULT_VOICE_SETTINGS: VoiceSettings = {
    shield: { pitch: 1.0, rate: 1.0, voiceURI: '' },
    skull: { pitch: 0.1, rate: 0.6, voiceURI: '' }, // Default Demon
    root: { pitch: 0.8, rate: 1.4, voiceURI: '' } // Default Robot
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onBack }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [genMode, setGenMode] = useState<GenerationMode>('CHAT');
  const [astraMode, setAstraMode] = useState<AstraMode>('shield'); 
  const [attachment, setAttachment] = useState<Attachment | null>(null);
  const [toolBoxOpen, setToolBoxOpen] = useState(false);
  const [featureMenuOpen, setFeatureMenuOpen] = useState(false);
  const [personalityMenuOpen, setPersonalityMenuOpen] = useState(false); // New state for bottom menu
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(false);
  const [scanningImage, setScanningImage] = useState<string | null>(null);
  const [isLiveMode, setIsLiveMode] = useState(false);

  // Voice Customization State
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(DEFAULT_VOICE_SETTINGS);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [configMode, setConfigMode] = useState<AstraMode>('shield'); // Which mode are we editing in settings

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isInitialized = useRef(false);
  const liveSessionRef = useRef<AstraLiveSession | null>(null);
  const personalityMenuRef = useRef<HTMLDivElement>(null);

  // --- INIT & LOAD HISTORY ---
  useEffect(() => {
    if (isInitialized.current) return;
    isInitialized.current = true;

    const savedHistory = localStorage.getItem('ASTRA_HISTORY');
    const savedAstraMode = localStorage.getItem('ASTRA_MODE') as AstraMode;
    const savedGenMode = localStorage.getItem('ASTRA_GEN_MODE') as GenerationMode;
    const savedVoiceSettings = localStorage.getItem('ASTRA_VOICE_SETTINGS');

    if(savedVoiceSettings) {
        try {
            setVoiceSettings(JSON.parse(savedVoiceSettings));
        } catch(e) { console.error("Error loading voice settings", e); }
    }

    if (savedHistory && savedAstraMode) {
       try {
           const parsedMsgs = JSON.parse(savedHistory);
           setMessages(parsedMsgs);
           setAstraMode(savedAstraMode);
           if(savedGenMode) setGenMode(savedGenMode);

           const history: Content[] = parsedMsgs
             .filter((m: Message) => m.id !== 'init' && !m.text.startsWith('>> IMAGE_GENERATED')) 
             .map((m: Message) => ({ 
                 role: m.role === Role.USER ? 'user' : 'model', 
                 parts: [{ text: m.text }] 
             }));

           initializeChat(savedGenMode || 'CHAT', savedAstraMode, history);
       } catch (e) {
           console.error("Corrupt History", e);
           startFreshSession('shield', 'CHAT');
       }
    } else {
       startFreshSession('shield', 'CHAT');
    }

    // Load Voices
    const loadVoices = () => {
        const voices = window.speechSynthesis.getVoices();
        setAvailableVoices(voices);
    };
    window.speechSynthesis.onvoiceschanged = loadVoices;
    loadVoices();

  }, []);

  // Close menus on click outside
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (personalityMenuRef.current && !personalityMenuRef.current.contains(event.target as Node)) {
              setPersonalityMenuOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- SAVE HISTORY ---
  useEffect(() => {
     if (isInitialized.current) {
        localStorage.setItem('ASTRA_HISTORY', JSON.stringify(messages));
        localStorage.setItem('ASTRA_MODE', astraMode);
        localStorage.setItem('ASTRA_GEN_MODE', genMode);
        localStorage.setItem('ASTRA_VOICE_SETTINGS', JSON.stringify(voiceSettings));
     }
  }, [messages, astraMode, genMode, voiceSettings]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- VOICE OUTPUT ---
  useEffect(() => {
      if (isVoiceEnabled && messages.length > 0) {
          const lastMsg = messages[messages.length - 1];
          if (lastMsg.role === Role.MODEL && !isLoading && lastMsg.id !== 'init') {
             speakText(lastMsg.text, astraMode, voiceSettings[astraMode]);
          }
      } else {
          speakText('', astraMode, undefined, true);
      }
  }, [messages, isVoiceEnabled, isLoading, astraMode, voiceSettings]);

  const startFreshSession = (newAstraMode: AstraMode, newGenMode: GenerationMode) => {
      initializeChat(newGenMode, newAstraMode);

      let greeting = INITIAL_GREETING_SHIELD;
      if (newAstraMode === 'skull') greeting = INITIAL_GREETING_SKULL;
      if (newAstraMode === 'root') greeting = INITIAL_GREETING_ROOT;

      setMessages([{
        id: 'init',
        role: Role.MODEL,
        text: greeting,
        timestamp: Date.now()
      }]);
  };

  const switchProtocol = (newMode: AstraMode) => {
      setAstraMode(newMode);
      startFreshSession(newMode, genMode);
  };

  const switchGenMode = (newMode: GenerationMode) => {
      setGenMode(newMode);
      setToolBoxOpen(false);
      setFeatureMenuOpen(false);
      startFreshSession(astraMode, newMode);
  };

  const clearHistory = () => {
      localStorage.removeItem('ASTRA_HISTORY');
      localStorage.removeItem('ASTRA_MODE');
      localStorage.removeItem('ASTRA_GEN_MODE');
      startFreshSession(astraMode, genMode);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          const reader = new FileReader();
          reader.onload = (ev) => {
              if (ev.target?.result) {
                  setAttachment({
                      file,
                      previewUrl: URL.createObjectURL(file),
                      base64: (ev.target.result as string).split(',')[1],
                      mimeType: file.type
                  });
              }
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSend = async () => {
    if ((!input.trim() && !attachment) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      text: input,
      image: attachment?.previewUrl,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    const currentAttachment = attachment;
    setAttachment(null);
    setIsLoading(true);

    if (genMode === 'ASTRA_DETECTION' && currentAttachment?.previewUrl) {
        setScanningImage(currentAttachment.previewUrl);
    }

    const modelMsgId = (Date.now() + 1).toString();
    const updateModelMsg = (text: string) => {
        setMessages(prev => {
            const exists = prev.find(m => m.id === modelMsgId);
            if (exists) return prev.map(m => m.id === modelMsgId ? { ...m, text } : m);
            return [...prev, { id: modelMsgId, role: Role.MODEL, text, timestamp: Date.now() }];
        });
    };

    try {
        if (genMode === 'IMAGE_EDIT') {
            updateModelMsg('>> RENDERING_VISUAL_DATA...');
            const imgBase64 = await generateEditedImage(userMsg.text, currentAttachment?.base64, currentAttachment?.mimeType);
            if (imgBase64) {
                setMessages(prev => prev.map(m => m.id === modelMsgId ? { ...m, text: ">> IMAGE_GENERATED.", image: imgBase64 } : m));
            } else {
                updateModelMsg(">> ERROR: RENDER FAILED.");
            }
        } else if (genMode === 'ASTRA_DETECTION') {
            if (currentAttachment) {
                const result = await runAstraDetection(currentAttachment, (text) => {});
                updateModelMsg(result);
            }
        } else {
            if (astraMode === 'root') updateModelMsg('> [EXECUTING_ROOT_COMMAND]...');
            await sendMessageToGemini(userMsg.text, currentAttachment, genMode, astraMode, updateModelMsg);
        }
    } catch (error) {
        updateModelMsg(">> SYSTEM FAILURE.");
    }
    setIsLoading(false);
    setScanningImage(null);
  };

  const toggleLiveSession = () => {
      if (isLiveMode) {
          liveSessionRef.current?.stop();
          liveSessionRef.current = null;
          setIsLiveMode(false);
      } else {
          setIsLiveMode(true);
          const session = new AstraLiveSession(astraMode);
          session.start(() => {
              setIsLiveMode(false);
              liveSessionRef.current = null;
          });
          liveSessionRef.current = session;
      }
  };

  const updateVoiceSetting = (key: keyof VoiceSettings['shield'], value: any) => {
      setVoiceSettings(prev => ({
          ...prev,
          [configMode]: {
              ...prev[configMode],
              [key]: value
          }
      }));
  };

  const getModeIcon = (m: GenerationMode) => {
      switch(m) {
          case 'DEEP_THINK': return BrainCircuit;
          case 'WEB_INTEL': return Globe;
          case 'SPEED_RUN': return Zap;
          case 'IMAGE_EDIT': return ImageIcon;
          case 'ASTRA_DETECTION': return ScanEye;
          case 'LOGO_ARCHITECT': return Wand2;
          default: return Terminal;
      }
  }

  const getThemeClasses = () => {
      switch(astraMode) {
          case 'skull': return 'bg-red-950 text-red-100 font-sans'; 
          case 'root': return 'bg-black text-red-500 font-terminal crt-scanlines'; 
          default: return 'bg-black text-white font-sans'; // Shield
      }
  };

  const features = [
      { id: 'CHAT', label: 'CORE CHAT', desc: 'Standard Astra Intelligence', icon: Terminal },
      { id: 'DEEP_THINK', label: 'DEEP REASONING', desc: 'Complex Problem Solving (High IQ)', icon: BrainCircuit },
      { id: 'WEB_INTEL', label: 'WEB INTEL', desc: 'Live Internet Access & Search', icon: Globe },
      { id: 'SPEED_RUN', label: 'SPEED RUN', desc: 'Lightning Fast Responses', icon: Zap },
      { id: 'IMAGE_EDIT', label: 'VISION EDIT', desc: 'Modify Images via Prompt', icon: ImageIcon },
      { id: 'ASTRA_DETECTION', label: 'DEEPFAKE SCAN', desc: 'Forensic Image Analysis', icon: ScanEye },
      { id: 'LOGO_ARCHITECT', label: 'LOGO ARCHITECT', desc: 'SVG Design & Vector Gen', icon: Wand2 },
  ];

  const CurrentModeIcon = getModeIcon(genMode);

  return (
    <div className={`fixed inset-0 z-50 flex flex-col h-[100dvh] w-full overflow-hidden ${getThemeClasses()}`}>

      {astraMode === 'root' && (
          <>
             <MatrixRain />
             <div className="fixed inset-0 z-0 flex items-center justify-center opacity-20 pointer-events-none animate-pulse">
                <Logo className="w-[500px] h-[500px]" isHackerMode={true} />
             </div>
             <div className="fixed inset-0 bg-red-500/5 z-0 pointer-events-none animate-pulse"></div>
          </>
      )}

      {/* --- HEADER --- */}
      <header className={`relative z-50 flex flex-col ${astraMode === 'root' ? 'bg-black/90' : 'bg-black/60 backdrop-blur-xl'} border-b border-white/10 transition-colors duration-500`}>

        <div className="flex items-center justify-between p-3 relative">
            {/* LEFT: LOGO & BACK */}
            <div className="flex items-center gap-3 w-1/4">
                <button onClick={onBack} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                    <Logo className="w-8 h-8" isHackerMode={astraMode === 'root'} />
                </button>
            </div>

            {/* CENTER: FEATURE DROPDOWN (STRICTLY CENTERED) */}
            <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-50">
                 <div className="relative">
                    <button 
                      onClick={() => setFeatureMenuOpen(!featureMenuOpen)}
                      className={`flex items-center gap-3 px-6 py-2.5 rounded-full border border-white/10 hover:border-astra-blue/50 transition-all group backdrop-blur-md shadow-lg ${astraMode === 'root' ? 'bg-red-900/40 text-red-500' : 'bg-white/5 text-astra-blue'}`}
                    >
                        <CurrentModeIcon size={18} className="group-hover:animate-pulse text-astra-saffron" />
                        <span className="font-orbitron text-xs font-bold tracking-wider hidden sm:inline-block">{genMode.replace('_', ' ')}</span>
                        <ChevronDown size={14} className={`transition-transform duration-300 opacity-60 ${featureMenuOpen ? 'rotate-180' : ''}`} />
                    </button>

                    <AnimatePresence>
                        {featureMenuOpen && (
                            <>
                            {/* Backdrop to close menu */}
                            <div className="fixed inset-0 z-40" onClick={() => setFeatureMenuOpen(false)}></div>

                            <motion.div
                              initial={{ opacity: 0, y: -10, scale: 0.95, x: "-50%" }}
                              animate={{ opacity: 1, y: 0, scale: 1, x: "-50%" }}
                              exit={{ opacity: 0, y: -10, scale: 0.95, x: "-50%" }}
                              className="absolute top-full left-1/2 mt-3 w-[280px] sm:w-[320px] bg-[#050505]/95 backdrop-blur-2xl border border-white/15 rounded-2xl overflow-hidden shadow-[0_10px_40px_rgba(0,0,0,0.8)] flex flex-col z-50"
                            >
                                <div className="px-5 py-3 bg-white/5 text-[10px] font-orbitron tracking-widest text-gray-400 uppercase border-b border-white/10 flex items-center justify-between">
                                    <span>Select Protocol</span>
                                    <Activity size={12} className="text-astra-blue" />
                                </div>
                                <div className="max-h-[60vh] overflow-y-auto custom-scrollbar p-2 space-y-1">
                                    {features.map((f) => (
                                        <button
                                          key={f.id}
                                          onClick={() => switchGenMode(f.id as GenerationMode)}
                                          className={`w-full flex items-center gap-4 px-3 py-3 rounded-xl transition-all text-left border border-transparent group ${genMode === f.id ? 'bg-astra-blue/10 border-astra-blue/30' : 'hover:bg-white/5 hover:border-white/10'}`}
                                        >
                                            <div className={`p-2 rounded-lg ${genMode === f.id ? 'bg-astra-saffron text-black' : 'bg-white/10 text-gray-400 group-hover:text-white'}`}>
                                                <f.icon size={18} />
                                            </div>
                                            <div className="flex-1">
                                                <div className={`font-orbitron text-xs font-bold tracking-wide ${genMode === f.id ? 'text-white' : 'text-gray-300 group-hover:text-white'}`}>
                                                    {f.label}
                                                </div>
                                                <div className="text-[10px] text-gray-500 font-tech leading-tight mt-0.5 group-hover:text-gray-400">
                                                    {f.desc}
                                                </div>
                                            </div>
                                            {genMode === f.id && <div className="w-1.5 h-1.5 rounded-full bg-astra-saffron shadow-[0_0_8px_#FF9933]"></div>}
                                        </button>
                                    ))}
                                </div>
                            </motion.div>
                            </>
                        )}
                    </AnimatePresence>
                 </div>
            </div>

            {/* RIGHT: TOOLS */}
            <div className="flex items-center justify-end gap-2 w-1/4">

                {/* PURGE BUTTON */}
                <button 
                    onClick={clearHistory}
                    className="flex items-center justify-center w-8 h-8 sm:w-auto sm:px-3 sm:py-2 bg-red-500/10 border border-red-500/30 hover:bg-red-500/20 hover:border-red-500/60 text-red-500 rounded-lg transition-all"
                    title="Wipe Chat Memory"
                >
                    <Trash2 size={16} />
                    <span className="hidden sm:inline ml-2 text-[10px] font-orbitron tracking-widest">PURGE</span>
                </button>

                <button 
                  onClick={() => setIsVoiceEnabled(!isVoiceEnabled)}
                  className={`p-2 rounded-lg transition-all border border-transparent ${isVoiceEnabled ? 'bg-astra-saffron text-black shadow-[0_0_10px_#FF9933]' : 'bg-white/5 text-gray-400 hover:text-white hover:border-white/20'}`}
                >
                    {isVoiceEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                </button>

                <button 
                   onClick={() => setToolBoxOpen(true)}
                   className="p-2 text-gray-400 hover:text-white transition-colors hover:rotate-90 duration-500"
                >
                    <Settings2 size={18} />
                </button>
            </div>
        </div>

        {/* SUB-HEADER STATUS BANNER (Cleaner) */}
        <div className="w-full h-1 bg-gradient-to-r from-transparent via-white/10 to-transparent"></div>

      </header>

      {/* --- MAIN CHAT AREA --- */}
      <main className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scroll-smooth pb-32">
        {messages.map((msg) => (
          <motion.div 
            key={msg.id}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className={`flex ${msg.role === Role.USER ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`max-w-[85%] md:max-w-[70%] relative group ${
                msg.role === Role.USER 
                 ? 'bg-white/10 border border-white/5 rounded-2xl rounded-tr-none' 
                 : astraMode === 'root' 
                   ? 'bg-black border border-green-500/30 rounded-none p-4 font-terminal text-green-400'
                   : 'bg-black/40 border border-white/10 rounded-2xl rounded-tl-none backdrop-blur-sm'
            } p-4`}>

                {/* Header for Message */}
                <div className="flex items-center gap-2 mb-2 opacity-50 text-[10px] font-orbitron tracking-widest">
                    {msg.role === Role.USER ? (
                        <><span>OPERATOR</span><div className="w-1 h-1 bg-astra-saffron rounded-full"></div></>
                    ) : (
                        <>
                          <div className={`w-1 h-1 rounded-full ${astraMode === 'skull' ? 'bg-red-500' : astraMode === 'root' ? 'bg-green-500' : 'bg-astra-blue'}`}></div>
                          <span>ASTRA // {astraMode.toUpperCase()}</span>
                        </>
                    )}
                    <span>{new Date(msg.timestamp).toLocaleTimeString()}</span>
                </div>

                {/* Attachments */}
                {msg.image && (
                    <div className="mb-3 rounded-lg overflow-hidden border border-white/10 relative group-hover:border-astra-blue/50 transition-colors">
                        <img src={msg.image} alt="Upload" className="max-w-full max-h-64 object-cover" />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
                    </div>
                )}

                {/* Text Content */}
                <div className={`prose prose-invert prose-p:leading-relaxed prose-pre:bg-black/50 prose-pre:border prose-pre:border-white/10 ${astraMode === 'root' ? 'font-terminal text-lg' : 'font-light'}`}>
                   {msg.id === messages[messages.length - 1].id && msg.role === Role.MODEL && isLoading ? (
                       <Typewriter text={msg.text} speed={astraMode === 'root' ? 5 : 15} />
                   ) : (
                       <ReactMarkdown
                        components={{
                            code({className, children, ...props}) {
                                const match = /language-(\w+)/.exec(className || '')
                                return match ? (
                                    <div className="relative group/code my-4">
                                        <div className="absolute -top-3 left-2 px-2 bg-gray-800 text-[10px] text-gray-400 rounded border border-gray-700 font-mono">
                                            {match[1].toUpperCase()}
                                        </div>
                                        <div className="bg-[#0d0d0d] p-4 rounded-lg border border-white/10 overflow-x-auto">
                                            <code className={`!bg-transparent text-sm font-mono text-gray-300 ${className}`} {...props}>
                                                {children}
                                            </code>
                                        </div>
                                    </div>
                                ) : (
                                    <code className="bg-white/10 px-1 py-0.5 rounded text-astra-saffron font-mono text-xs" {...props}>
                                        {children}
                                    </code>
                                )
                            }
                        }}
                       >
                           {msg.text}
                       </ReactMarkdown>
                   )}
                </div>
            </div>
          </motion.div>
        ))}
        {isLoading && (
            <div className="flex justify-start">
               <div className="flex items-center gap-1 h-6">
                   <div className="w-1 h-1 bg-astra-blue rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                   <div className="w-1 h-1 bg-astra-blue rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                   <div className="w-1 h-1 bg-astra-blue rounded-full animate-bounce"></div>
               </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </main>

      {/* --- INPUT AREA --- */}
      <div className={`p-4 ${astraMode === 'root' ? 'bg-black border-t-2 border-green-500' : 'bg-black/60 backdrop-blur-xl border-t border-white/10'}`}>

         {/* ATTACHMENT PREVIEW */}
         <AnimatePresence>
             {attachment && (
                 <motion.div 
                   initial={{ opacity: 0, y: 10 }}
                   animate={{ opacity: 1, y: 0 }}
                   exit={{ opacity: 0, y: 10 }}
                   className="absolute bottom-full left-4 mb-4 bg-gray-900 border border-white/20 p-2 rounded-lg flex items-center gap-3"
                 >
                     <div className="w-10 h-10 rounded overflow-hidden">
                         <img src={attachment.previewUrl} className="w-full h-full object-cover" />
                     </div>
                     <div className="text-xs max-w-[150px] truncate">{attachment.file.name}</div>
                     <button onClick={() => setAttachment(null)} className="p-1 hover:bg-white/20 rounded-full"><X size={14} /></button>
                 </motion.div>
             )}
         </AnimatePresence>

         <div className="max-w-4xl mx-auto flex gap-2 sm:gap-3 items-end">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*"
              onChange={handleFileSelect}
            />

            {/* NEW: PERSONALITY SWITCHER (BOTTOM) */}
            <div className="relative" ref={personalityMenuRef}>
               <button 
                  onClick={() => setPersonalityMenuOpen(!personalityMenuOpen)}
                  className={`p-3 rounded-xl transition-all border ${
                      astraMode === 'skull' ? 'border-red-500/50 text-red-500 bg-red-500/10' :
                      astraMode === 'root' ? 'border-green-500/50 text-green-500 bg-green-500/10' :
                      'border-white/10 text-astra-blue bg-white/5 hover:bg-white/10'
                  }`}
                  title="Switch Personality (Shield / Roast / Root)"
               >
                   {astraMode === 'shield' && <Shield size={20} />}
                   {astraMode === 'skull' && <Skull size={20} />}
                   {astraMode === 'root' && <Terminal size={20} />}
               </button>

               <AnimatePresence>
                  {personalityMenuOpen && (
                      <motion.div 
                         initial={{ opacity: 0, y: 10, scale: 0.95 }}
                         animate={{ opacity: 1, y: -10, scale: 1 }}
                         exit={{ opacity: 0, y: 10, scale: 0.95 }}
                         className="absolute bottom-full left-0 mb-2 w-56 bg-[#0a0a0a] border border-white/20 rounded-xl overflow-hidden shadow-[0_0_30px_rgba(0,0,0,0.8)] z-50 flex flex-col backdrop-blur-xl"
                      >
                          <div className="px-4 py-3 text-[10px] text-gray-500 font-orbitron tracking-widest border-b border-white/10 bg-white/5">
                              PERSONALITY MATRIX
                          </div>

                          <button 
                             onClick={() => { switchProtocol('shield'); setPersonalityMenuOpen(false); }}
                             className={`flex items-center gap-3 px-4 py-3 hover:bg-white/10 transition-colors text-left border-b border-white/5 ${astraMode === 'shield' ? 'text-astra-blue' : 'text-gray-400'}`}
                          >
                              <Shield size={16} />
                              <div className="flex-1">
                                  <div className="font-bold text-xs">SHIELD</div>
                                  <div className="text-[10px] opacity-60">Standard Defense</div>
                              </div>
                              {astraMode === 'shield' && <div className="w-1.5 h-1.5 rounded-full bg-astra-blue"></div>}
                          </button>

                          <button 
                             onClick={() => { switchProtocol('skull'); setPersonalityMenuOpen(false); }}
                             className={`flex items-center gap-3 px-4 py-3 hover:bg-red-900/20 transition-colors text-left border-b border-white/5 ${astraMode === 'skull' ? 'text-red-500' : 'text-gray-400'}`}
                          >
                              <Flame size={16} />
                              <div className="flex-1">
                                  <div className="font-bold text-xs">ROAST / SKULL</div>
                                  <div className="text-[10px] opacity-60">Toxic & Savage</div>
                              </div>
                              {astraMode === 'skull' && <div className="w-1.5 h-1.5 rounded-full bg-red-500"></div>}
                          </button>

                          <button 
                             onClick={() => { switchProtocol('root'); setPersonalityMenuOpen(false); }}
                             className={`flex items-center gap-3 px-4 py-3 hover:bg-green-900/20 transition-colors text-left ${astraMode === 'root' ? 'text-green-500' : 'text-gray-400'}`}
                          >
                              <Terminal size={16} />
                              <div className="flex-1">
                                  <div className="font-bold text-xs">ROOT SHELL</div>
                                  <div className="text-[10px] opacity-60">Hacker CLI</div>
                              </div>
                              {astraMode === 'root' && <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>}
                          </button>
                      </motion.div>
                  )}
               </AnimatePresence>
            </div>

            <button 
              onClick={() => fileInputRef.current?.click()}
              className={`p-3 rounded-xl transition-colors ${astraMode === 'root' ? 'border border-green-500 text-green-500 hover:bg-green-500/20' : 'bg-white/5 text-gray-400 hover:text-astra-blue hover:bg-white/10'}`}
            >
                <Paperclip size={20} />
            </button>

            <button
               onClick={toggleLiveSession}
               className={`p-3 rounded-xl transition-all relative ${isLiveMode ? 'bg-red-500 text-white animate-pulse' : astraMode === 'root' ? 'border border-green-500 text-green-500 hover:bg-green-500/20' : 'bg-white/5 text-gray-400 hover:text-astra-blue hover:bg-white/10'}`}
            >
                {isLiveMode ? <StopCircle size={20} /> : <Radio size={20} />}
            </button>

            <div className={`flex-1 flex items-center gap-2 p-3 rounded-xl ${astraMode === 'root' ? 'border border-green-500 bg-black' : 'bg-white/5 border border-white/5 focus-within:border-astra-blue/50'}`}>
                {astraMode === 'root' && <span className="text-green-500 font-terminal mr-1">{'>'}</span>}
                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => {
                      if(e.key === 'Enter' && !e.shiftKey) {
                          e.preventDefault();
                          handleSend();
                      }
                  }}
                  placeholder={astraMode === 'skull' ? "Say something stupid..." : astraMode === 'root' ? "ENTER_COMMAND_MATRIX..." : "Message Astra..."}
                  className={`bg-transparent w-full resize-none outline-none max-h-32 text-sm ${astraMode === 'root' ? 'font-terminal text-green-500 placeholder-green-800' : 'text-white placeholder-gray-500'}`}
                  rows={1}
                />
            </div>

            <button 
              onClick={handleSend}
              disabled={isLoading || (!input.trim() && !attachment)}
              className={`p-3 rounded-xl transition-all disabled:opacity-50 ${
                  astraMode === 'root' 
                  ? 'bg-green-600 text-black hover:bg-green-500' 
                  : 'bg-astra-blue text-black hover:bg-astra-blue/80 shadow-[0_0_15px_rgba(0,240,255,0.3)]'
              }`}
            >
                <Send size={20} />
            </button>
         </div>
      </div>

      {/* --- SETTINGS MODAL (Reused for Config) --- */}
      <AnimatePresence>
          {toolBoxOpen && (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-4"
              >
                  <div className="bg-gray-900 border border-white/10 w-full max-w-md rounded-2xl p-6 relative shadow-2xl">
                      <button onClick={() => setToolBoxOpen(false)} className="absolute top-4 right-4 text-gray-500 hover:text-white"><X size={20} /></button>

                      <h2 className="font-orbitron text-xl mb-6 flex items-center gap-2">
                          <Settings2 className="text-astra-saffron" />
                          SYSTEM CONFIG
                      </h2>

                      {/* Config Mode Tabs */}
                      <div className="flex bg-black/50 rounded-lg p-1 mb-6">
                         {(['shield', 'skull', 'root'] as AstraMode[]).map(m => (
                             <button
                               key={m}
                               onClick={() => setConfigMode(m)}
                               className={`flex-1 py-2 text-xs font-bold rounded uppercase transition-colors ${configMode === m ? 'bg-white/10 text-astra-blue' : 'text-gray-500'}`}
                             >
                                 {m}
                             </button>
                         ))}
                      </div>

                      <div className="space-y-6">
                          <div>
                              <label className="text-xs font-tech text-gray-400 mb-2 block">VOICE PROFILE</label>
                              <select 
                                className="w-full bg-black border border-white/20 rounded p-2 text-sm text-white"
                                value={voiceSettings[configMode].voiceURI}
                                onChange={(e) => updateVoiceSetting('voiceURI', e.target.value)}
                              >
                                  <option value="">System Default</option>
                                  {availableVoices.map(v => (
                                      <option key={v.voiceURI} value={v.voiceURI}>{v.name} ({v.lang})</option>
                                  ))}
                              </select>
                          </div>

                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="text-xs font-tech text-gray-400 mb-2 block">PITCH: {voiceSettings[configMode].pitch.toFixed(1)}</label>
                                  <input 
                                    type="range" min="0" max="2" step="0.1"
                                    value={voiceSettings[configMode].pitch}
                                    onChange={(e) => updateVoiceSetting('pitch', parseFloat(e.target.value))}
                                    className="w-full accent-astra-saffron"
                                  />
                              </div>
                              <div>
                                  <label className="text-xs font-tech text-gray-400 mb-2 block">SPEED: {voiceSettings[configMode].rate.toFixed(1)}</label>
                                  <input 
                                    type="range" min="0.1" max="2" step="0.1"
                                    value={voiceSettings[configMode].rate}
                                    onChange={(e) => updateVoiceSetting('rate', parseFloat(e.target.value))}
                                    className="w-full accent-astra-blue"
                                  />
                              </div>
                          </div>
                      </div>

                      <div className="mt-8 pt-6 border-t border-white/10 flex justify-end">
                          <button onClick={() => setToolBoxOpen(false)} className="px-6 py-2 bg-white text-black font-bold rounded hover:bg-gray-200">
                              SAVE CHANGES
                          </button>
                      </div>
                  </div>
              </motion.div>
          )}
      </AnimatePresence>

      {/* --- SCANNERS & OVERLAYS --- */}
      {scanningImage && <AstraScanner imageUrl={scanningImage} />}
      {isVoiceEnabled && !isLoading && <div className="absolute top-20 right-4 pointer-events-none opacity-50"><VoiceVisualizer /></div>}

    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Send, Mic, Image as ImageIcon, Terminal, X, 
  Activity, ChevronLeft, LayoutGrid, BrainCircuit, 
  Globe, Zap, ScanEye, Wand2, Paperclip, Shield, Skull, Cpu, 
  Volume2, VolumeX, Trash2, Radio, StopCircle, Settings2, ChevronDown,
  AlertTriangle, CheckCircle2, Flame
} from 'lucide-react';
import { Message, Role, CodeSnippet, Attachment, GenerationMode, AstraMode, VoiceSettings } from '../types';
import { 
  sendMessageToGemini, 
  initializeChat, 
  generateEditedImage, 
  runAstraDetection,
  speakText,
  AstraLiveSession
} from '../services/geminiService';
import { 
  INITIAL_GREETING_SHIELD, 
  INITIAL_GREETING_SKULL, 
  INITIAL_GREETING_ROOT 
} from '../constants';
import ReactMarkdown from 'react-markdown';
import { Logo } from './Logo';
import { motion, AnimatePresence } from 'framer-motion';
import { Typewriter } from './Typewriter';
import { AstraScanner } from './AstraScanner';
import { MatrixRain } from './MatrixRain';
import { VoiceVisualizer } from './VoiceVisualizer';
import { Content } from '@google/genai';

interface ChatInterfaceProps {
  onBack: () => void;
}

const DEFAULT_VOICE_SETTINGS: VoiceSettings = {
    shield: { pitch: 1.0, rate: 1.0, voiceURI: '' },
    skull: { pitch: 0.1, rate: 0.6, voiceURI: '' }, // Default Demon
    root: { pitch: 0.8, rate: 1.4, voiceURI: '' } // Default Robot
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onBack }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [genMode, setGenMode] = useState<GenerationMode>('CHAT');
  const [astraMode, setAstraMode] = useState<AstraMode>('shield'); 
  const [attachment, setAttachment] = useState<Attachment | null>(null);
  const [toolBoxOpen, setToolBoxOpen] = useState(false);
  const [featureMenuOpen, setFeatureMenuOpen] = useState(false);
  const [personalityMenuOpen, setPersonalityMenuOpen] = useState(false); // New state for bottom menu
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(false);
  const [scanningImage, setScanningImage] = useState<string | null>(null);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [isInputFocused, setIsInputFocused] = useState(false); // Focus state for input animation

  // Voice Customization State
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(DEFAULT_VOICE_SETTINGS);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [configMode, setConfigMode] = useState<AstraMode>('shield'); // Which mode are we editing in settings

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isInitialized = useRef(false);
  const liveSessionRef = useRef<AstraLiveSession | null>(null);
  const personalityMenuRef = useRef<HTMLDivElement>(null);

  // --- INIT & LOAD HISTORY ---
  useEffect(() => {
    if (isInitialized.current) return;
    isInitialized.current = true;

    const savedHistory = localStorage.getItem('ASTRA_HISTORY');
    const savedAstraMode = localStorage.getItem('ASTRA_MODE') as AstraMode;
    const savedGenMode = localStorage.getItem('ASTRA_GEN_MODE') as GenerationMode;
    const savedVoiceSettings = localStorage.getItem('ASTRA_VOICE_SETTINGS');

    if(savedVoiceSettings) {
        try {
            setVoiceSettings(JSON.parse(savedVoiceSettings));
        } catch(e) { console.error("Error loading voice settings", e); }
    }

    if (savedHistory && savedAstraMode) {
       try {
           const parsedMsgs = JSON.parse(savedHistory);
           setMessages(parsedMsgs);
           setAstraMode(savedAstraMode);
           if(savedGenMode) setGenMode(savedGenMode);

           const history: Content[] = parsedMsgs
             .filter((m: Message) => m.id !== 'init' && !m.text.startsWith('>> IMAGE_GENERATED')) 
             .map((m: Message) => ({ 
                 role: m.role === Role.USER ? 'user' : 'model', 
                 parts: [{ text: m.text }] 
             }));

           initializeChat(savedGenMode || 'CHAT', savedAstraMode, history);
       } catch (e) {
           console.error("Corrupt History", e);
           startFreshSession('shield', 'CHAT');
       }
    } else {
       startFreshSession('shield', 'CHAT');
    }

    // Load Voices
    const loadVoices = () => {
        const voices = window.speechSynthesis.getVoices();
        setAvailableVoices(voices);
    };
    window.speechSynthesis.onvoiceschanged = loadVoices;
    loadVoices();

  }, []);

  // Close menus on click outside
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (personalityMenuRef.current && !personalityMenuRef.current.contains(event.target as Node)) {
              setPersonalityMenuOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- SAVE HISTORY ---
  useEffect(() => {
     if (isInitialized.current) {
        localStorage.setItem('ASTRA_HISTORY', JSON.stringify(messages));
        localStorage.setItem('ASTRA_MODE', astraMode);
        localStorage.setItem('ASTRA_GEN_MODE', genMode);
        localStorage.setItem('ASTRA_VOICE_SETTINGS', JSON.stringify(voiceSettings));
     }
  }, [messages, astraMode, genMode, voiceSettings]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- VOICE OUTPUT ---
  useEffect(() => {
      if (isVoiceEnabled && messages.length > 0) {
          const lastMsg = messages[messages.length - 1];
          if (lastMsg.role === Role.MODEL && !isLoading && lastMsg.id !== 'init') {
             speakText(lastMsg.text, astraMode, voiceSettings[astraMode]);
          }
      } else {
          speakText('', astraMode, undefined, true);
      }
  }, [messages, isVoiceEnabled, isLoading, astraMode, voiceSettings]);

  const startFreshSession = (newAstraMode: AstraMode, newGenMode: GenerationMode) => {
      initializeChat(newGenMode, newAstraMode);

      let greeting = INITIAL_GREETING_SHIELD;
      if (newAstraMode === 'skull') greeting = INITIAL_GREETING_SKULL;
      if (newAstraMode === 'root') greeting = INITIAL_GREETING_ROOT;

      setMessages([{
        id: 'init',
        role: Role.MODEL,
        text: greeting,
        timestamp: Date.now()
      }]);
  };

  const switchProtocol = (newMode: AstraMode) => {
      setAstraMode(newMode);
      startFreshSession(newMode, genMode);
  };

  const switchGenMode = (newMode: GenerationMode) => {
      setGenMode(newMode);
      setToolBoxOpen(false);
      setFeatureMenuOpen(false);
      startFreshSession(astraMode, newMode);
  };

  const clearHistory = () => {
      localStorage.removeItem('ASTRA_HISTORY');
      localStorage.removeItem('ASTRA_MODE');
      localStorage.removeItem('ASTRA_GEN_MODE');
      startFreshSession(astraMode, genMode);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          const reader = new FileReader();
          reader.onload = (ev) => {
              if (ev.target?.result) {
                  setAttachment({
                      file,
                      previewUrl: URL.createObjectURL(file),
                      base64: (ev.target.result as string).split(',')[1],
                      mimeType: file.type
                  });
              }
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSend = async () => {
    if ((!input.trim() && !attachment) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      text: input,
      image: attachment?.previewUrl,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    const currentAttachment = attachment;
    setAttachment(null);
    setIsLoading(true);

    if (genMode === 'ASTRA_DETECTION' && currentAttachment?.previewUrl) {
        setScanningImage(currentAttachment.previewUrl);
    }

    const modelMsgId = (Date.now() + 1).toString();
    const updateModelMsg = (text: string) => {
        setMessages(prev => {
            const exists = prev.find(m => m.id === modelMsgId);
            if (exists) return prev.map(m => m.id === modelMsgId ? { ...m, text } : m);
            return [...prev, { id: modelMsgId, role: Role.MODEL, text, timestamp: Date.now() }];
        });
    };

    try {
        if (genMode === 'IMAGE_EDIT') {
            updateModelMsg('>> RENDERING_VISUAL_DATA...');
            const imgBase64 = await generateEditedImage(userMsg.text, currentAttachment?.base64, currentAttachment?.mimeType);
            if (imgBase64) {
                setMessages(prev => prev.map(m => m.id === modelMsgId ? { ...m, text: ">> IMAGE_GENERATED.", image: imgBase64 } : m));
            } else {
                updateModelMsg(">> ERROR: RENDER FAILED.");
            }
        } else if (genMode === 'ASTRA_DETECTION') {
            if (currentAttachment) {
                const result = await runAstraDetection(currentAttachment, (text) => {});
                updateModelMsg(result);
            }
        } else {
            if (astraMode === 'root') updateModelMsg('> [EXECUTING_ROOT_COMMAND]...');
            await sendMessageToGemini(userMsg.text, currentAttachment, genMode, astraMode, updateModelMsg);
        }
    } catch (error) {
        updateModelMsg(">> SYSTEM FAILURE.");
    }
    setIsLoading(false);
    setScanningImage(null);
  };

  const toggleLiveSession = () => {
      if (isLiveMode) {
          liveSessionRef.current?.stop();
          liveSessionRef.current = null;
          setIsLiveMode(false);
      } else {
          setIsLiveMode(true);
          const session = new AstraLiveSession(astraMode);
          session.start(() => {
              setIsLiveMode(false);
              liveSessionRef.current = null;
          });
          liveSessionRef.current = session;
      }
  };

  const updateVoiceSetting = (key: keyof VoiceSettings['shield'], value: any) => {
      setVoiceSettings(prev => ({
          ...prev,
          [configMode]: {
              ...prev[configMode],
              [key]: value
          }
      }));
  };

  const getModeIcon = (m: GenerationMode) => {
      switch(m) {
          case 'DEEP_THINK': return BrainCircuit;
          case 'WEB_INTEL': return Globe;
          case 'SPEED_RUN': return Zap;
          case 'IMAGE_EDIT': return ImageIcon;
          case 'ASTRA_DETECTION': return ScanEye;
          case 'LOGO_ARCHITECT': return Wand2;
          default: return Terminal;
      }
  }

  const getThemeClasses = () => {
      switch(astraMode) {
          case 'skull': return 'bg-red-950 text-red-100 font-sans'; 
          case 'root': return 'bg-black text-red-500 font-terminal crt-scanlines'; 
          default: return 'bg-black text-white font-sans'; // Shield
      }
  };

  const features = [
      { id: 'CHAT', label: 'CORE CHAT', desc: 'Standard Astra Intelligence', icon: Terminal },
      { id: 'DEEP_THINK', label: 'DEEP REASONING', desc: 'Complex Problem Solving (High IQ)', icon: BrainCircuit },
      { id: 'WEB_INTEL', label: 'WEB INTEL', desc: 'Live Internet Access & Search', icon: Globe },
      { id: 'SPEED_RUN', label: 'SPEED RUN', desc: 'Lightning Fast Responses', icon: Zap },
      { id: 'IMAGE_EDIT', label: 'VISION EDIT', desc: 'Modify Images via Prompt', icon: ImageIcon },
      { id: 'ASTRA_DETECTION', label: 'DEEPFAKE SCAN', desc: 'Forensic Image Analysis', icon: ScanEye },
      { id: 'LOGO_ARCHITECT', label: 'LOGO ARCHITECT', desc: 'SVG Design & Vector Gen', icon: Wand2 },
  ];

  const CurrentModeIcon = getModeIcon(genMode);

  return (
    <div className={`fixed inset-0 z-50 flex flex-col h-[100dvh] w-full overflow-hidden ${getThemeClasses()}`}>

      {astraMode === 'root' && (
          <>
             <MatrixRain />
             <div className="fixed inset-0 z-0 flex items-center justify-center opacity-20 pointer-events-none animate-pulse">
