import { GoogleGenAI, Chat, GenerateContentResponse, Content, Tool, LiveServerMessage, Modality } from "@google/genai";
import { 
  ASTRA_SHIELD_INSTRUCTION, 
  ASTRA_SKULL_INSTRUCTION, 
  ASTRA_ROOT_INSTRUCTION 
} from '../constants';
import { Attachment, GenerationMode, AstraMode, VoiceProfile } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let chatInstance: Chat | null = null;
let currentModelId = 'gemini-3-pro-preview';

// --- Get System Instruction Based on Astra Mode ---
const getSystemPrompt = (astraMode: AstraMode) => {
    switch(astraMode) {
        case 'skull': return ASTRA_SKULL_INSTRUCTION;
        case 'root': return ASTRA_ROOT_INSTRUCTION;
        case 'shield': default: return ASTRA_SHIELD_INSTRUCTION;
    }
};

// --- 1. Chat & Text Logic ---

const getModelConfig = (genMode: GenerationMode, astraMode: AstraMode) => {
  const systemInstruction = getSystemPrompt(astraMode);

  switch (genMode) {
    case 'DEEP_THINK':
      return {
        model: 'gemini-3-pro-preview',
        config: {
          systemInstruction,
          thinkingConfig: { thinkingBudget: 32768 }
        }
      };
    case 'WEB_INTEL':
      return {
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction,
          tools: [{ googleSearch: {} } as Tool]
        }
      };
    case 'SPEED_RUN':
      return {
        model: 'gemini-2.5-flash-lite-latest',
        config: {
          systemInstruction,
          temperature: 0.7
        }
      };
    case 'LOGO_ARCHITECT':
        return {
             model: 'gemini-3-pro-preview',
             config: { systemInstruction }
        };
    case 'CHAT':
    default:
      return {
        model: 'gemini-2.5-flash', // Optimized for speed/efficiency
        config: {
          systemInstruction,
          temperature: astraMode === 'root' ? 0.2 : 0.9, // More deterministic for Root
        }
      };
  }
};

export const initializeChat = (
  genMode: GenerationMode = 'CHAT', 
  astraMode: AstraMode = 'shield',
  history?: Content[]
) => {
  const { model, config } = getModelConfig(genMode, astraMode);
  currentModelId = model;

  chatInstance = ai.chats.create({
    model: model,
    config: config,
    history: history
  });
};

export const sendMessageToGemini = async (
  userMessage: string,
  attachment: Attachment | null,
  genMode: GenerationMode,
  astraMode: AstraMode,
  onStream: (text: string) => void
): Promise<string> => {

  if (!chatInstance) {
      initializeChat(genMode, astraMode);
  }

  let fullResponse = "";

  try {
    let result;

    if (attachment) {
       const { model, config } = getModelConfig(genMode, astraMode);
       const response = await ai.models.generateContentStream({
        model: model,
        contents: {
          parts: [
            { inlineData: { data: attachment.base64, mimeType: attachment.mimeType } },
            { text: userMessage }
          ]
        },
        config: config
       });
       result = response;
    } else {
       result = await chatInstance!.sendMessageStream({ message: userMessage });
    }

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullResponse += text;
