// --- 2. Text to Speech (Browser API) ---
export const speakText = (
    text: string, 
    astraMode: AstraMode = 'shield', 
    customProfile?: VoiceProfile,
    stop: boolean = false
) => {
    if (stop) {
        window.speechSynthesis.cancel();
        return;
    }
    // Cancel previous speech to avoid overlap
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);

    // Default settings
    let pitch = 1.1;
    let rate = 1.1;
    let voiceName = '';

    if (astraMode === 'skull') {
        rate = 0.6; 
        pitch = 0.1; 
    } else if (astraMode === 'root') {
        rate = 1.4; 
        pitch = 0.8; 
    }

    // Apply custom profile override if provided
    if (customProfile) {
        pitch = customProfile.pitch;
        rate = customProfile.rate;
        voiceName = customProfile.voiceURI;
    }

    utterance.pitch = pitch;
    utterance.rate = rate;

    const voices = window.speechSynthesis.getVoices();
    let selectedVoice = null;

    if (voiceName) {
        selectedVoice = voices.find(v => v.voiceURI === voiceName || v.name === voiceName);
    }

    // Fallback logic if no custom voice selected or found
    if (!selectedVoice) {
        selectedVoice = voices.find(v => v.name.includes('Google US English') || v.name.includes('Microsoft Mark') || v.name.includes('Samantha'));
    }

    if (selectedVoice) utterance.voice = selectedVoice;

    window.speechSynthesis.speak(utterance);
};


