// --- 5. GEMINI LIVE (Real-time Bidirectional Audio) ---

export class AstraLiveSession {
  private inputAudioContext: AudioContext | null = null;
  private outputAudioContext: AudioContext | null = null;
  private mediaStream: MediaStream | null = null;
  private processor: ScriptProcessorNode | null = null;
  private source: MediaStreamAudioSourceNode | null = null;
  private nextStartTime = 0;
  private astraMode: AstraMode;

  constructor(mode: AstraMode) {
    this.astraMode = mode;
  }

  async start(onClose: () => void) {
    // Initialize Audio Contexts
    // Input needs to be 16kHz for Gemini
    this.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    // Output from Gemini is 24kHz
    this.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Get System Instruction
    const systemInstruction = getSystemPrompt(this.astraMode);

    try {
        // Connect to Gemini Live
        const sessionPromise = ai.live.connect({
            model: 'gemini-2.5-flash-native-audio-preview-09-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                systemInstruction: systemInstruction,
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } // Or Puck, Charon, Fenrir, Zephyr
                }
            },
            callbacks: {
                onopen: async () => {
                    console.log("ASTRA LIVE: CONNECTED");
                    this.startRecording(sessionPromise);
                },
                onmessage: async (message: LiveServerMessage) => {
                    const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (audioData) {
                        await this.playAudio(audioData);
                    }
                    const turnComplete = message.serverContent?.turnComplete;
                },
                onclose: () => {
                    console.log("ASTRA LIVE: CLOSED");
                    this.stop();
                    onClose();
                },
                onerror: (err) => {
                    console.error("ASTRA LIVE ERROR", err);
                    this.stop();
                    onClose();
                }
            }
        });
    } catch (err) {
        console.error("Failed to connect to Live API", err);
        onClose();
    }
  }

  private async startRecording(sessionPromise: Promise<any>) {
      if (!this.inputAudioContext) return;

      this.mediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      this.source = this.inputAudioContext.createMediaStreamSource(this.mediaStream);
      this.processor = this.inputAudioContext.createScriptProcessor(4096, 1, 1);

      this.processor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          const pcmData = this.convertFloat32ToInt16(inputData);
          const base64 = this.arrayBufferToBase64(pcmData.buffer);

          sessionPromise.then(session => {
              session.sendRealtimeInput({
                  media: {
                      mimeType: 'audio/pcm;rate=16000',
                      data: base64
                  }
              });
          });
      };

      this.source.connect(this.processor);
      this.processor.connect(this.inputAudioContext.destination);
  }

  private async playAudio(base64: string) {
      if (!this.outputAudioContext) return;

      const arrayBuffer = this.base64ToArrayBuffer(base64);
      const float32Data = this.convertInt16ToFloat32(new Int16Array(arrayBuffer));
      const audioBuffer = this.outputAudioContext.createBuffer(1, float32Data.length, 24000);
      audioBuffer.getChannelData(0).set(float32Data);

      const source = this.outputAudioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(this.outputAudioContext.destination);

      // Queue playback
      const currentTime = this.outputAudioContext.currentTime;
      if (this.nextStartTime < currentTime) {
          this.nextStartTime = currentTime;
      }
      source.start(this.nextStartTime);
      this.nextStartTime += audioBuffer.duration;
  }

  stop() {
      this.processor?.disconnect();
      this.source?.disconnect();
      this.mediaStream?.getTracks().forEach(t => t.stop());
      this.inputAudioContext?.close();
      this.outputAudioContext?.close();

      this.processor = null;
      this.source = null;
      this.mediaStream = null;
      this.inputAudioContext = null;
      this.outputAudioContext = null;
  }

  // Utils
  private convertFloat32ToInt16(float32: Float32Array) {
      const int16 = new Int16Array(float32.length);
      for (let i = 0; i < float32.length; i++) {
          int16[i] = Math.max(-1, Math.min(1, float32[i])) * 0x7FFF;
      }
      return int16;
  }

  private convertInt16ToFloat32(int16: Int16Array) {
      const float32 = new Float32Array(int16.length);
      for (let i = 0; i < int16.length; i++) {
          float32[i] = int16[i] / 0x7FFF;
      }
      return float32;
  }

  private arrayBufferToBase64(buffer: ArrayBuffer) {
      let binary = '';
      const bytes = new Uint8Array(buffer);
      for (let i = 0; i < bytes.byteLength; i++) {
          binary += String.fromCharCode(bytes[i]);
      }
      return btoa(binary);
  }

  private base64ToArrayBuffer(base64: string) {
      const binary = atob(base64);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) {
          bytes[i] = binary.charCodeAt(i);
      }
      return bytes.buffer;
  }
}

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';

interface TypewriterProps {
  text: string;
  speed?: number;
  className?: string;
}

export const Typewriter: React.FC<TypewriterProps> = ({ text, speed = 5, className }) => {
  const [displayedText, setDisplayedText] = useState('');

  // Reset if the text content seems to be from a completely new message source
  // We use a simple heuristic: if the new text is shorter than what we displayed, it's likely a reset/new message.
  useEffect(() => {
    if (text.length < displayedText.length) {
      setDisplayedText('');
    }
  }, [text, displayedText.length]);

  useEffect(() => {
    const timer = setInterval(() => {
      setDisplayedText((prev) => {
        if (prev.length < text.length) {
          // Calculate how many characters to add to catch up smoothly
          // If the stream is very fast, we add more characters per tick to prevent lagging behind
          const diff = text.length - prev.length;
          const chunk = Math.max(1, Math.floor(diff / 5)); 
          return text.substring(0, prev.length + chunk);
        }
        return prev;
      });
    }, speed);

    return () => clearInterval(timer);
  }, [text, speed]);

  return (
    <div className={className}>
      <ReactMarkdown
        components={{
            code({className, children, ...props}) {
                const match = /language-(\w+)/.exec(className || '')
                return match ? (
                    <div className="relative group/code my-4">
                        <div className="absolute -top-3 left-2 px-2 bg-gray-800 text-[10px] text-gray-400 rounded border border-gray-700 font-mono">
                            {match[1].toUpperCase()}
                        </div>
                        <div className="bg-[#0d0d0d] p-4 rounded-lg border border-white/10 overflow-x-auto">
                            <code className={`!bg-transparent text-sm font-mono text-gray-300 ${className}`} {...props}>
                                {children}
                            </code>
                        </div>
                    </div>
                ) : (
                    <code className="bg-white/10 px-1 py-0.5 rounded text-astra-saffron font-mono text-xs" {...props}>
                        {children}
                    </code>
                )
            }
        }}
      >
        {displayedText}
      </ReactMarkdown>
      {displayedText.length < text.length && (
          <span className="inline-block w-2 h-4 ml-1 bg-astra-saffron animate-pulse align-middle"></span>
      )}
    </div>
  );
};

