export const sendMessageToGemini = async (
  userMessage: string,
  attachment: Attachment | null,
  genMode: GenerationMode,
  astraMode: AstraMode,
  onStream: (text: string) => void
): Promise<string> => {

  if (!chatInstance) {
      initializeChat(genMode, astraMode);
  }

  let fullResponse = "";

  try {
    let result;

    if (attachment) {
       const { model, config } = getModelConfig(genMode, astraMode);
       const response = await ai.models.generateContentStream({
        model: model,
        contents: {
          parts: [
            { inlineData: { data: attachment.base64, mimeType: attachment.mimeType } },
            { text: userMessage }
          ]
        },
        config: config
       });
       result = response;
    } else {
       result = await chatInstance!.sendMessageStream({ message: userMessage });
    }

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullResponse += text;
        onStream(fullResponse);
      }
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    const errorMsg = "RTMS CONNECTION INTERRUPTED. NETWORK ANOMALY DETECTED. 🚫";
    onStream(errorMsg);
    return errorMsg;
  }

  return fullResponse;
};

