export const sendMessageToGemini = async (
  userMessage: string,
  attachment: Attachment | null,
  genMode: GenerationMode,
  astraMode: AstraMode,
  onStream: (text: string) => void
): Promise<string> => {

  if (!chatInstance) {
      initializeChat(genMode, astraMode);
  }

  let fullResponse = "";

  try {
    let result;

    if (attachment) {
       const { model, config } = getModelConfig(genMode, astraMode);
       const response = await ai.models.generateContentStream({
        model: model,
        contents: {
          parts: [
            { inlineData: { data: attachment.base64, mimeType: attachment.mimeType } },
            { text: userMessage }
          ]
        },
        config: config
       });
       result = response;
    } else {
       result = await chatInstance!.sendMessageStream({ message: userMessage });
    }

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullResponse += text;
        onStream(fullResponse);
      }
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    const errorMsg = "RTMS CONNECTION INTERRUPTED. NETWORK ANOMALY DETECTED. 🚫";
    onStream(errorMsg);
    return errorMsg;
  }

  return fullResponse;
};

// --- 2. Enhanced TTS (Gemini Model) ---
export const speakText = async (
    text: string, 
    astraMode: AstraMode = 'shield', 
    customProfile?: VoiceProfile,
    stop: boolean = false
) => {
    // Stop any existing playback immediately
    if (ttsSource) {
        try { ttsSource.stop(); } catch (e) {}
        ttsSource = null;
    }

    if (stop || !text) return;

    // Initialize Audio Context if needed
    if (!ttsAudioContext) {
        ttsAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    // Resume context if suspended (browser autoplay policy)
    if (ttsAudioContext.state === 'suspended') {
        await ttsAudioContext.resume();
    }

    // Determine Voice
    // Shield -> Kore (Balanced, Female-sounding)
    // Skull -> Puck (Mischievous/Aggressive)
    // Root -> Fenrir (Deep/Authoritative)
    let voiceName = 'Kore';
    if (astraMode === 'skull') voiceName = 'Puck';
    if (astraMode === 'root') voiceName = 'Fenrir';

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: { parts: [{ text: text }] },
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName }
                    }
                }
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

        if (base64Audio) {
            const audioBuffer = await decodeAudioData(base64Audio, ttsAudioContext);
            const source = ttsAudioContext.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(ttsAudioContext.destination);
            source.start();
            ttsSource = source;

            // Clean up reference when done
            source.onended = () => {
                if (ttsSource === source) ttsSource = null;
            };
        }
    } catch (e) {
        console.error("TTS Generation Failed", e);
    }
};

// Helper for decoding Gemini Audio (which doesn't have headers)
const decodeAudioData = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }

    // Gemini 2.5 TTS Output is raw PCM 24kHz Mono (usually)
    // We need to verify if the API returns raw PCM or WAV. 
    // The Live API returns raw PCM. generateContent with 'AUDIO' modality returns Base64 encoded audio bytes.
    // For gemini-2.5-flash-preview-tts, it usually returns a wav-like or raw buffer.
    // Let's assume standard PCM decoding or try ctx.decodeAudioData if it has headers (WAV).
    // The documentation examples for TTS show standard decoding might work if headers are present, 
    // BUT Live API examples use manual Float32 conversion.
    // Let's try manual PCM conversion for reliability with Gemini audio streams, similar to Live API.

    // Actually, gemini-2.5-flash-preview-tts output usually works with Web Audio decodeAudioData 
    // IF the model sends a WAV container. If it sends RAW PCM, we need manual decoding.
    // Safest bet for single-shot TTS (unlike Live stream) is that it might be raw.
    // Let's reuse the logic from LiveSession but adapted for a single buffer.

    // However, createBuffer requires length.
    // 16-bit PCM = 2 bytes per sample.
    const numChannels = 1;
    const sampleRate = 24000;

    // Try native decode first (if it's WAV/MP3)
    try {
        // Copy buffer because decodeAudioData detaches it
        const bufferCopy = bytes.buffer.slice(0);
        return await ctx.decodeAudioData(bufferCopy);
    } catch (e) {
        // Fallback to Raw PCM decoding
        const dataInt16 = new Int16Array(bytes.buffer);
        const frameCount = dataInt16.length;
        const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
        const channelData = audioBuffer.getChannelData(0);

        for (let i = 0; i < frameCount; i++) {
             channelData[i] = dataInt16[i] / 32768.0;
        }
        return audioBuffer;
    }
};


