                      : (astraMode === 'root' ? '#15803d' : 'rgba(255, 255, 255, 0.05)'),
                  boxShadow: isInputFocused 
                      ? (astraMode === 'root' ? '0 0 10px rgba(34, 197, 94, 0.3)' : (astraMode === 'skull' ? '0 0 10px rgba(239, 68, 68, 0.3)' : '0 0 15px rgba(0, 240, 255, 0.2)'))
