  AlertTriangle, CheckCircle2, Flame, Search, ScanLine, Code2, Copy, Check, Download
} from 'lucide-react';
import { Message, Role, CodeSnippet, Attachment, GenerationMode, AstraMode, VoiceSettings, GroundingMetadata } from '../types';
import { 
  sendMessageToGemini, 
  initializeChat, 
  generateEditedImage, 
  runAstraDetection,
  speakText,
  AstraLiveSession
} from '../services/geminiService';
import { 
