            ) : (
                <div className="text-xs text-gray-500 italic">No specific anomalies flagged yet...</div>
            )}
        </div>
        {report && (
            <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="bg-white/5 rounded-lg p-3 border border-white/10"
            >
                 <div className="text-[10px] font-orbitron text-astra-blue tracking-widest mb-2 flex items-center gap-2">
                    <Search size={12} /> FORENSIC_ANALYSIS
